#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to multiply two polynomials
void multiplyPolynomials(double *q, int n, double *t, int m, double *result, int *degree) {
    int i, j;
    *degree = n + m;
    for (i = 0; i <= *degree; i++) {
        result[i] = 0;
    }
    for (i = 0; i <= n; i++) {
        for (j = 0; j <= m; j++) {
            result[i + j] += q[i] * t[j];
        }
    }
}

// Function to integrate a polynomial
void integratePolynomial(double *q, int n, double *result, int *degree) {
    int i;
    *degree = n + 1;
    for (i = 0; i <= *degree; i++) {
        result[i] = 0;
    }
    for (i = 0; i <= n; i++) {
        result[i + 1] = q[i] / (i + 1);
    }
}

// Function to solve the system of linear equations
void solveLinearEquations(double **coefficients, double *constants, int n, double *solution) {
    int i, j, k;
    double determinant, temp;
    for (i = 0; i < n; i++) {
        determinant = coefficients[i][i];
        for (j = i + 1; j < n; j++) {
            temp = coefficients[j][i] / determinant;
            for (k = i; k < n; k++) {
                coefficients[j][k] -= temp * coefficients[i][k];
            }
            constants[j] -= temp * constants[i];
        }
    }
    for (i = n - 1; i >= 0; i--) {
        solution[i] = constants[i];
        for (j = i + 1; j < n; j++) {
            solution[i] -= coefficients[i][j] * solution[j];
        }
        solution[i] /= coefficients[i][i];
    }
}

