// COMPLETE, COMPILABLE C++ code
#include <iostream>
#include <vector>
using namespace std;

// Function to multiply two polynomials
vector<double> multiplyPolynomials(vector<double> q, vector<double> t) {
    vector<double> result(q.size() + t.size() - 1, 0);
    for (int i = 0; i < q.size(); i++) {
        for (int j = 0; j < t.size(); j++) {
            result[i + j] += q[i] * t[j];
        }
    }
    return result;
}

// Function to integrate a polynomial
vector<double> integratePolynomial(vector<double> q) {
    vector<double> result(q.size() + 1, 0);
    for (int i = 0; i < q.size(); i++) {
        result[i + 1] = q[i] / (i + 1);
    }
    return result;
}

// Function to solve the system of linear equations
vector<double> solveLinearEquations(vector<vector<double>> coefficients, vector<double> constants) {
    int n = coefficients.size();
    vector<double> solution(n, 0);
    for (int i = 0; i < n; i++) {
        double determinant = coefficients[i][i];
        for (int j = i + 1; j < n; j++) {
            double temp = coefficients[j][i] / determinant;
            for (int k = i; k < n; k++) {
                coefficients[j][k] -= temp * coefficients[i][k];
            }
            constants[j] -= temp * constants[i];
        }
    }
    for (int i = n - 1; i >= 0; i--) {
        solution[i] = constants[i];
        for (int j = i + 1; j < n; j++) {
            solution[i] -= coefficients[i][j] * solution[j];
        }
        solution[i] /= coefficients[i][i];
    }
    return solution;
}

int main() {
    int k, n, m;
    cin >> k;
    for (int i = 0; i < k; i++) {
        cin >> n;
        vector<double> q(n + 1, 0);
        for (int j = 0; j <= n; j++) {
            cin >> q[j];
        }
        cin >> m;
        vector<double> t(m + 1, 0);
        for (int j = 0; j <= m; j++) {
            cin >> t[j];
        }
        vector<double> result = multiplyPolynomials(q, t);
        vector<vector<double>> coefficients(result.size(), vector<double>(result.size(), 0));
        vector<double> constants(result.size(), 0);
        for (int j = 0; j < result.size(); j++) {
            coefficients[j][j] = 1;
            constants[j] = result[j];
        }
        vector<double> solution = solveLinearEquations(coefficients, constants);
        cout << result.size() - 1 << endl;
        for (int j = 0; j < result.size(); j++) {
            cout << solution[j] << " ";
        }
        cout << endl;
    }
    return 0;
}

